다음은 화면에 문자 'x'와 문자 'y'를 출력하는 프로그램이다. 화면에 출력되는 문자들의 총 개수는?

```c
#include <stdio.h>
int main() {
    int i, j, k;
    for (i = 0; i <= 10; i++) {
        for (j = 0; j <= 10 - i; j++) {
            putchar('x');
        }
        for (k = 0; k <= 2 * i; k++) {
            putchar('y');
        }
        puts("");
    }
    return 0;
}
```

아래 프로그램의 실행 결과와 출력되는 result 값은?

```c
#include <stdio.h>
int main() {
    int i = 2, result = 0;
    while (++i < 60) {
        if ((i % 3 != 0) && (i % 5 != 0)) {
            continue;
        }
        result += i;
    }
    printf("result = %d\n", result);
    return 0;
}
```

